117: void UdpProxyFilter::ClusterInfo::removeSession(ActiveSession* session) {
118:   if (session->host().has_value()) {
119:     // First remove from the host to sessions map, in case the host was resolved.
120:     ASSERT(host_to_sessions_[&session->host().value().get()].count(session) == 1);
121:     auto host_sessions_it = host_to_sessions_.find(&session->host().value().get());
122:     host_sessions_it->second.erase(session);
123:     if (host_sessions_it->second.empty()) {
124:       host_to_sessions_.erase(host_sessions_it);
125:     }
126:   }
127: 
128:   session->onSessionComplete();
129: 
130:   // Now remove it from the primary map.
131:   ASSERT(sessions_.count(session) == 1);
132:   sessions_.erase(session);
133: }
