136: UdpProxyFilter::ClusterInfo::createSession(Network::UdpRecvData::LocalPeerAddresses&& addresses,
137:                                            const Upstream::HostConstSharedPtr& optional_host,
138:                                            bool defer_socket_creation) {
139:   if (!cluster_.info()
140:            ->resourceManager(Upstream::ResourcePriority::Default)
141:            .connections()
142:            .canCreate()) {
143:     ENVOY_LOG(debug, "cannot create new connection.");
144:     cluster_.info()->trafficStats()->upstream_cx_overflow_.inc();
145:     return nullptr;
146:   }
147: 
148:   if (defer_socket_creation) {
149:     ASSERT(!optional_host);
150:     return createSessionWithOptionalHost(std::move(addresses), nullptr);
151:   }
152: 
153:   if (optional_host) {
154:     return createSessionWithOptionalHost(std::move(addresses), optional_host);
155:   }
156: 
157:   auto host = chooseHost(addresses.peer_, nullptr);
158:   if (host == nullptr) {
159:     ENVOY_LOG(debug, "cannot find any valid host.");
160:     cluster_.info()->trafficStats()->upstream_cx_none_healthy_.inc();
161:     return nullptr;
162:   }
163: 
164:   return createSessionWithOptionalHost(std::move(addresses), host);
165: }
