167: UdpProxyFilter::ActiveSession* UdpProxyFilter::ClusterInfo::createSessionWithOptionalHost(
168:     Network::UdpRecvData::LocalPeerAddresses&& addresses,
169:     const Upstream::HostConstSharedPtr& host) {
170:   ActiveSessionPtr new_session;
171:   if (filter_.config_->tunnelingConfig()) {
172:     ASSERT(!host);
173:     new_session = std::make_unique<TunnelingActiveSession>(*this, std::move(addresses));
174:   } else {
175:     new_session = std::make_unique<UdpActiveSession>(*this, std::move(addresses), host);
176:   }
177: 
178:   new_session->createFilterChain();
179:   if (new_session->onNewSession()) {
180:     auto new_session_ptr = new_session.get();
181:     sessions_.emplace(std::move(new_session));
182:     return new_session_ptr;
183:   }
184: 
185:   new_session->onSessionComplete();
186:   return nullptr;
187: }
