203: Network::FilterStatus UdpProxyFilter::StickySessionClusterInfo::onData(Network::UdpRecvData& data) {
204:   bool defer_socket = filter_.config_->hasSessionFilters() || filter_.config_->tunnelingConfig();
205:   const auto active_session_it = sessions_.find(data.addresses_);
206:   ActiveSession* active_session;
207:   if (active_session_it == sessions_.end()) {
208:     active_session = createSession(std::move(data.addresses_), nullptr, defer_socket);
209:     if (active_session == nullptr) {
210:       return Network::FilterStatus::StopIteration;
211:     }
212:   } else {
213:     active_session = active_session_it->get();
214:     // We defer the socket creation when the session includes filters, so the filters can be
215:     // iterated before choosing the host, to allow dynamically choosing upstream host. Due to this,
216:     // we can't perform health checks during a session.
217:     // TODO(ohadvano): add similar functionality that is performed after session filter chain
218:     // iteration to signal filters about the unhealthy host, or replace the host during the session.
219:     if (!defer_socket &&
220:         active_session->host().value().get().coarseHealth() == Upstream::Host::Health::Unhealthy) {
221:       // If a host becomes unhealthy, we optimally would like to replace it with a new session
222:       // to a healthy host. We may eventually want to make this behavior configurable, but for now
223:       // this will be the universal behavior.
224:       auto host = chooseHost(data.addresses_.peer_, nullptr);
225:       if (host != nullptr && host->coarseHealth() != Upstream::Host::Health::Unhealthy &&
226:           host.get() != &active_session->host().value().get()) {
227:         ENVOY_LOG(debug, "upstream session unhealthy, recreating the session");
228:         removeSession(active_session);
229:         active_session = createSession(std::move(data.addresses_), host, false);
230:       } else {
231:         // In this case we could not get a better host, so just keep using the current session.
232:         ENVOY_LOG(trace, "upstream session unhealthy, but unable to get a better host");
233:       }
234:     }
235:   }
236: 
237:   active_session->onData(data);
238: 
239:   return Network::FilterStatus::StopIteration;
240: }
