417: bool UdpProxyFilter::ActiveSession::onNewSession() {
418:   if (cluster_.filter_.config_->accessLogFlushInterval().has_value() &&
419:       !cluster_.filter_.config_->sessionAccessLogs().empty()) {
420:     access_log_flush_timer_ =
421:         cluster_.filter_.read_callbacks_->udpListener().dispatcher().createTimer(
422:             [this] { onAccessLogFlushInterval(); });
423:     rearmAccessLogFlushTimer();
424:   }
425: 
426:   // Set UUID for the session. This is used for logging and tracing.
427:   udp_session_info_.setStreamIdProvider(std::make_shared<StreamInfo::StreamIdProviderImpl>(
428:       cluster_.filter_.config_->randomGenerator().uuid()));
429: 
430:   for (auto& active_read_filter : read_filters_) {
431:     if (active_read_filter->initialized_) {
432:       // The filter may call continueFilterChain() in onNewSession(), causing next
433:       // filters to iterate onNewSession(), so check that it was not called before.
434:       continue;
435:     }
436: 
437:     active_read_filter->initialized_ = true;
438:     auto status = active_read_filter->read_filter_->onNewSession();
439:     if (status == ReadFilterStatus::StopIteration) {
440:       return true;
441:     }
442:   }
