718: void HttpUpstreamImpl::setRequestEncoder(Http::RequestEncoder& request_encoder, bool is_ssl) {
719:   request_encoder_ = &request_encoder;
720:   request_encoder_->getStream().addCallbacks(*this);
721: 
722:   const std::string& scheme =
723:       is_ssl ? Http::Headers::get().SchemeValues.Https : Http::Headers::get().SchemeValues.Http;
724: 
725:   std::string host = tunnel_config_.proxyHost(downstream_info_);
726:   const auto* dynamic_port =
727:       downstream_info_.filterState()->getDataReadOnly<StreamInfo::UInt32Accessor>(
728:           "udp.connect.proxy_port");
729:   if (dynamic_port != nullptr && dynamic_port->value() > 0 && dynamic_port->value() <= 65535) {
730:     absl::StrAppend(&host, ":", std::to_string(dynamic_port->value()));
731:   } else if (tunnel_config_.proxyPort().has_value()) {
732:     absl::StrAppend(&host, ":", std::to_string(tunnel_config_.proxyPort().value()));
733:   }
734: 
735:   auto headers = Http::RequestHeaderMapImpl::create();
736:   headers->addReferenceKey(Http::Headers::get().Scheme, scheme);
737:   headers->addReferenceKey(Http::Headers::get().Host, host);
738: 
739:   if (tunnel_config_.usePost()) {
740:     headers->addReferenceKey(Http::Headers::get().Method, "POST");
741:     headers->addReferenceKey(Http::Headers::get().Path, tunnel_config_.postPath());
742:   } else {
743:     // The Envoy HTTP/2 and HTTP/3 clients expect the request header map to be in the form of HTTP/1
744:     // upgrade to issue an extended CONNECT request.
745:     headers->addReferenceKey(Http::Headers::get().Method, "GET");
746:     headers->addReferenceKey(Http::Headers::get().Connection, "Upgrade");
747:     headers->addReferenceKey(Http::Headers::get().Upgrade, "connect-udp");
748:     headers->addReferenceKey(Http::Headers::get().CapsuleProtocol, "?1");
749:     const std::string target_tunnel_path = resolveTargetTunnelPath();
750:     headers->addReferenceKey(Http::Headers::get().Path, target_tunnel_path);
751:   }
752: 
753:   tunnel_config_.headerEvaluator().evaluateHeaders(*headers, {downstream_info_.getRequestHeaders()},
754:                                                    downstream_info_);
755: 
756:   const auto status = request_encoder_->encodeHeaders(*headers, false);
757:   // Encoding can only fail on missing required request headers.
758:   ASSERT(status.ok());
759: }
