782: void HttpUpstreamImpl::resetEncoder(Network::ConnectionEvent event, bool by_downstream) {
783:   if (!request_encoder_) {
784:     return;
785:   }
786: 
787:   request_encoder_->getStream().removeCallbacks(*this);
788:   if (by_downstream) {
789:     request_encoder_->getStream().resetStream(Http::StreamResetReason::LocalReset);
790:   }
791: 
792:   request_encoder_ = nullptr;
793: 
794:   // If we did not receive a valid CONNECT response yet we treat this as a pool
795:   // failure, otherwise we forward the event downstream.
796:   if (tunnel_creation_callbacks_.has_value()) {
797:     tunnel_creation_callbacks_.value().get().onStreamFailure();
798:     return;
799:   }
800: 
801:   if (!by_downstream) {
802:     upstream_callbacks_.onUpstreamEvent(event);
803:   }
804: }
