909: bool UdpProxyFilter::TunnelingActiveSession::createConnectionPool() {
910:   ASSERT(conn_pool_factory_);
911: 
912:   // Check this here because the TCP conn pool will queue our request waiting for a connection that
913:   // will never be released.
914:   if (!cluster_.cluster_.info()
915:            ->resourceManager(Upstream::ResourcePriority::Default)
916:            .connections()
917:            .canCreate()) {
918:     udp_session_info_.setResponseFlag(StreamInfo::CoreResponseFlag::UpstreamOverflow);
919:     cluster_.cluster_.info()->trafficStats()->upstream_cx_overflow_.inc();
920:     return false;
921:   }
922: 
923:   if (connect_attempts_ >= cluster_.filter_.config_->tunnelingConfig()->maxConnectAttempts()) {
924:     udp_session_info_.setResponseFlag(StreamInfo::CoreResponseFlag::UpstreamRetryLimitExceeded);
925:     cluster_.cluster_.info()->trafficStats()->upstream_cx_connect_attempts_exceeded_.inc();
926:     return false;
927:   } else if (connect_attempts_ >= 1) {
928:     cluster_.cluster_.info()->trafficStats()->upstream_rq_retry_.inc();
929:   }
930: 
931:   conn_pool_ = conn_pool_factory_->createConnPool(
932:       cluster_.cluster_, load_balancer_context_.get(), *cluster_.filter_.config_->tunnelingConfig(),
933:       *this, udp_session_info_, cluster_.filter_.config_->flushAccessLogOnTunnelConnected(),
934:       cluster_.filter_.config_->sessionAccessLogs());
935: 
936:   if (conn_pool_) {
937:     connecting_ = true;
938:     connect_attempts_++;
939:     udp_session_info_.setAttemptCount(connect_attempts_);
940:     conn_pool_->newStream(*this);
941:     return true;
942:   }
943: 
944:   udp_session_info_.setResponseFlag(StreamInfo::CoreResponseFlag::NoHealthyUpstream);
945:   return false;
946: }
