948: void UdpProxyFilter::TunnelingActiveSession::onStreamFailure(
949:     ConnectionPool::PoolFailureReason reason, absl::string_view failure_reason,
950:     Upstream::HostDescriptionConstSharedPtr) {
951:   ENVOY_LOG(debug, "Failed to create upstream stream: {}", failure_reason);
952: 
953:   conn_pool_.reset();
954:   upstream_.reset();
955: 
956:   switch (reason) {
957:   case ConnectionPool::PoolFailureReason::Overflow:
958:   case ConnectionPool::PoolFailureReason::LocalConnectionFailure:
959:     onUpstreamEvent(Network::ConnectionEvent::LocalClose);
960:     break;
961:   case ConnectionPool::PoolFailureReason::Timeout:
962:     udp_session_info_.setResponseFlag(StreamInfo::CoreResponseFlag::UpstreamConnectionFailure);
963:     onUpstreamEvent(Network::ConnectionEvent::RemoteClose);
964:     break;
965:   case ConnectionPool::PoolFailureReason::RemoteConnectionFailure:
966:     if (connecting_) {
967:       udp_session_info_.setResponseFlag(StreamInfo::CoreResponseFlag::UpstreamConnectionFailure);
968:     }
