93:     void expectSetIpTransparentSocketOption() {
94:       EXPECT_CALL(*socket_->io_handle_, setOption(_, _, _, _))
95:           .WillRepeatedly(Invoke([this](int level, int optname, const void* optval,
96:                                         socklen_t) -> Api::SysCallIntResult {
97:             sock_opts_[level][optname] = *reinterpret_cast<const int*>(optval);
98:             return Api::SysCallIntResult{0, 0};
99:           }));
100:     }
101: 
102:     void expectWriteToUpstream(const std::string& data, int sys_errno = 0,
103:                                const Network::Address::Ip* local_ip = nullptr,
104:                                bool expect_connect = false, int connect_sys_errno = 0) {
105:       EXPECT_CALL(*idle_timer_, enableTimer(parent_.config_->sessionTimeout(), nullptr));
106:       if (expect_connect) {
107:         EXPECT_CALL(*socket_->io_handle_, connect(_))
108:             .WillOnce(Invoke([connect_sys_errno]() -> Api::SysCallIntResult {
109:               if (!connect_sys_errno) {
110:                 return Api::SysCallIntResult{0, 0};
111:               } else {
112:                 return Api::SysCallIntResult{-1, connect_sys_errno};
113:               }
114:             }));
115:       } else {
116:         EXPECT_CALL(*socket_->io_handle_, connect(_)).Times(0);
117:       }
118:       if (!connect_sys_errno) {
119:         EXPECT_CALL(*socket_->io_handle_, sendmsg(_, 1, 0, _, _))
120:             .WillOnce(Invoke(
121:                 [this, data, local_ip, sys_errno](
122:                     const Buffer::RawSlice* slices, uint64_t, int,
123:                     const Network::Address::Ip* self_ip,
124:                     const Network::Address::Instance& peer_address) -> Api::IoCallUint64Result {
125:                   EXPECT_EQ(data, absl::string_view(static_cast<const char*>(slices[0].mem_),
126:                                                     slices[0].len_));
127:                   EXPECT_EQ(peer_address, *upstream_address_);
128:                   if (local_ip == nullptr) {
129:                     EXPECT_EQ(nullptr, self_ip);
130:                   } else {
131:                     EXPECT_EQ(self_ip->addressAsString(), local_ip->addressAsString());
132:                   }
133:                   // For suppression of clang-tidy NewDeleteLeaks rule, don't use the ternary
134:                   // operator.
135:                   if (sys_errno == 0) {
136:                     return makeNoError(data.size());
137:                   } else {
138:                     return makeError(sys_errno);
139:                   }
140:                 }));
141:       }
142:     }
143: 
144:     void recvDataFromUpstream(const std::string& data, int recv_sys_errno = 0,
145:                               int send_sys_errno = 0) {
146:       EXPECT_CALL(*idle_timer_, enableTimer(parent_.config_->sessionTimeout(), nullptr));
147: 
148:       if (parent_.expect_gro_) {
149:         EXPECT_CALL(*socket_->io_handle_, supportsUdpGro());
150:       }
151:       EXPECT_CALL(*socket_->io_handle_, supportsMmsg()).Times(1u);
152:       // Return the datagram.
153:       EXPECT_CALL(*socket_->io_handle_, recvmsg(_, 1, _, _))
154:           .WillOnce(
155:               Invoke([this, data, recv_sys_errno](
156:                          Buffer::RawSlice* slices, const uint64_t, uint32_t,
157:                          Network::IoHandle::RecvMsgOutput& output) -> Api::IoCallUint64Result {
158:                 if (recv_sys_errno != 0) {
159:                   return makeError(recv_sys_errno);
160:                 } else {
161:                   ASSERT(data.size() <= slices[0].len_);
162:                   memcpy(slices[0].mem_, data.data(), data.size());
163:                   output.msg_[0].peer_address_ = upstream_address_;
164:                   return makeNoError(data.size());
165:                 }
166:               }));
167:       if (recv_sys_errno == 0) {
168:         // Send the datagram downstream.
169:         EXPECT_CALL(parent_.callbacks_.udp_listener_, send(_))
170:             .WillOnce(Invoke([data, send_sys_errno](
171:                                  const Network::UdpSendData& send_data) -> Api::IoCallUint64Result {
172:               // TODO(mattklein123): Verify peer/local address.
173:               EXPECT_EQ(send_data.buffer_.toString(), data);
174:               if (send_sys_errno == 0) {
175:                 send_data.buffer_.drain(send_data.buffer_.length());
176:                 return makeNoError(data.size());
177:               } else {
178:                 return makeError(send_sys_errno);
179:               }
180:             }));
181:         // Return an EAGAIN result.
182:         EXPECT_CALL(*socket_->io_handle_, recvmsg(_, 1, _, _))
183:             .WillOnce(Return(ByMove(
184:                 Api::IoCallUint64Result(0, Network::IoSocketError::getIoSocketEagainError()))));
185:       }
186: 
187:       // Kick off the receive.
188:       file_event_cb_(Event::FileReadyType::Read);
189:     }
190: 
191:     UdpProxyFilterTest& parent_;
192:     const Network::Address::InstanceConstSharedPtr upstream_address_;
193:     Event::MockTimer* idle_timer_{};
194:     NiceMock<Network::MockSocket>* socket_;
195:     std::map<int, std::map<int, int>> sock_opts_;
196:     Event::FileReadyCb file_event_cb_;
197:   };
