859:   EXPECT_EQ(1, config_->stats().downstream_sess_active_.value());
860: 
861:   // Timing out the 1st session should allow us to create another.
862:   test_sessions_[0].idle_timer_->invokeCallback();
863:   EXPECT_EQ(1, config_->stats().downstream_sess_total_.value());
864:   EXPECT_EQ(0, config_->stats().downstream_sess_active_.value());
865:   expectSessionCreate(upstream_address_);
866:   test_sessions_[1].expectWriteToUpstream("hello", 0, nullptr, true);
